import { useState } from 'react'

interface ToggleButtonProps {
  label: string
  onToggle?: (pressed: boolean) => void
}

export const ToggleButton = ({ label, onToggle }: ToggleButtonProps) => {
  const [pressed, setPressed] = useState(false)

  const handleClick = () => {
    const next = !pressed
    setPressed(next)
    onToggle?.(next)
  }

  return (
    <button
      type="button"
      aria-pressed={pressed}
      onClick={handleClick}
    >
      {label}
    </button>
  )
}
